async function toggleFavorite(e,s){const o=document.getElementById(s);if(!(!o||!e))try{const t=window.API_CONFIG?.BASE_URL||"http://localhost:3001/api",n=await fetch(`${t}/user/readings/${e}/favorite`,{method:"PATCH",credentials:"include",headers:{"Content-Type":"application/json",Authorization:`Bearer ${window.Auth?.token||localStorage.getItem("auth_token")}`}});if(!n.ok)throw new Error("Failed to toggle favorite");const a=(await n.json()).is_favorite,i=o.querySelector(".favorite-icon");a?(i.textContent="\u2B50",o.innerHTML='<span class="favorite-icon">\u2B50</span> Obl\xEDben\xE9',o.classList.remove("btn--glass"),o.classList.add("btn--primary")):(i.textContent="\u2606",o.innerHTML='<span class="favorite-icon">\u2606</span> P\u0159idat do obl\xEDben\xFDch',o.classList.remove("btn--primary"),o.classList.add("btn--glass")),window.showToast&&window.showToast(a?"\u2B50 P\u0159id\xE1no do obl\xEDben\xFDch":"Odebr\xE1no z obl\xEDben\xFDch")}catch(t){console.error("Error toggling favorite:",t),window.showToast&&window.showToast("\u274C Nepoda\u0159ilo se ulo\u017Eit","error")}}window.toggleFavorite=toggleFavorite;
